#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef __int128 ll;
#define int ll
const int Mod=20130427,N=1e5+10;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
inline void UP(int &x){x<0?x+=Mod:0;}
vector<int> L,R;int B,pw[N],dp[N][2][2],ss[N],g[N][2][2];
inline void Init(int n)
{
	pw[0]=1;rep(1,n,i)pw[i]=1ll*pw[i-1]*B%Mod;
	ss[0]=1;rep(1,n,i){DN(ss[i]=ss[i-1]+pw[i]);}
}
inline int S1(int x){return (1ll*x*(x+1)/2)%Mod;}
inline int S(vector<int> &a)
{
	memset(dp,0,sizeof(dp));memset(g,0,sizeof(g));
	g[0][0][0]=dp[0][0][0]=g[0][0][1]=dp[0][0][1]=0;
	g[0][1][0]=dp[0][1][0]=S1(B-1);g[0][1][1]=dp[0][1][1]=S1(a[0]);
	int n=a.size(),pre=a[0];for(int i=1;i<n;++i)
	{
		g[i][0][0]=g[i-1][0][0]+g[i-1][1][0];
		g[i][1][0]=(B-1)*(g[i-1][0][0]+g[i-1][1][0])+S1(B-1)*ss[i]*pw[i];
		g[i][0][1]=g[i-1][0][!a[i]]+g[i-1][1][!a[i]];
		if(a[i])g[i][1][1]=(a[i]-1)*(g[i-1][0][0]+g[i-1][1][0])+g[i-1][1][1]+g[i-1][0][1]+a[i]*ss[i]*(pre+1)+S1(a[i]-1)*ss[i]*pw[i];
		
		
		dp[i][0][0]=dp[i-1][0][0]+dp[i-1][1][0]+g[i][0][0];
		dp[i][0][1]=dp[i-1][0][!a[i]]+dp[i-1][1][!a[i]]+g[i][0][!a[i]];
		dp[i][1][0]=(dp[i-1][0][0]+dp[i-1][1][0])*(B-1)+g[i][1][0];
		if(a[i])dp[i][1][1]=(dp[i-1][0][0]+dp[i-1][1][0])*(a[i]-1)+dp[i-1][0][1]+dp[i-1][1][1]+g[i][1][1];
		
		pre=(a[i]*pw[i]+pre)%Mod;
		rep(0,1,x)rep(0,1,y)UP(dp[i][x][y]%=Mod),UP(g[i][x][y]%=Mod);
	}
	int ans=0;
	for(int i=0;i<n-1;++i)DN(ans+=dp[i][1][0]);//,printf("%d\n",dp[i][1][1]);
	DN(ans+=dp[n-1][1][1]);
//	#define dp g
//	rep(0,3,i){
//		printf("debug :: %d :: \n",i);
//		printf("|%d,%d|\n|%d,%d|\n",dp[i][0][0],dp[i][0][1],dp[i][1][0],dp[i][1][1]);
//		puts(">>>>>\n");
//	}
//	#undef dp
//	printf("QAQ :: %d\n",ans);
	return ans;
}
signed main()
{
//	FIN("2.in");
	B=read();int k;
	k=read();L.resize(k);drep(k-1,0,i)L[i]=read();
	k=read();R.resize(k);drep(k-1,0,i)R[i]=read();
	for(unsigned i=0;i<L.size();++i){if(!L[i])L[i]=B-1;else{--L[i];break;}}
	if(!(*prev(L.end())))L.pop_back();
//	printf("QAQ :: ");for(int v:L)printf("%d ",v);puts("")	;
	Init(max(L.size(),R.size()));
//	S(R);return 0;
//	printf("%d %d\n",S(L),S(R));
	printf("%lld\n",(long long)((S(R)-S(L)+Mod)%Mod));
}
